/* insertMptnma */
insert
into MPTNMA(
COMPKEY, PTNRKEY, OWNERKY
, PTNATCD, PTSTPKY, PTNRTYP, PTNAMLC, PTNAMKO
, PTNAMEN, PTADDR1, PTADDR2, PTADDR3, PTNRLAT
, PTNRLON, PTCIYNM, PTREGNM, PTTELN1, PTTELN2
, PTTELN3, PTTAXCD, PTPOSBX, PTPOSCD, PTREPNM
, PTREPTL, PTREPEM, PTMANNM, PTMANTL, PTMANEM
, PTNGRO1, PTNGRO2, PTNGRO3, PTINMAG, POSTSTM
, PTBLCTC, PTNRORD, PTUSEYN
, CREDATE, CRETIME, CREUSER
, LMODATE, LMOTIME, LMOUSER )
values
( #{compkey}, #{ptnrkey}, IFNULL(#{ownerky}, " ")
, #{ptnatcd}, #{ptstpky}, #{ptnrtyp}, #{ptnamlc}, #{ptnamko}
, #{ptnamen}, #{ptaddr1}, #{ptaddr2}, #{ptaddr3}, #{ptnrlat}
, #{ptnrlon}, #{ptciynm}, #{ptregnm}, #{ptteln1}, #{ptteln2}
, #{ptteln3}, #{pttaxcd}, #{ptposbx}, #{ptposcd}, #{ptrepnm}
, #{ptreptl}, #{ptrepem}, #{ptmannm}, #{ptmantl}, #{ptmanem}
, #{ptngro1}, #{ptngro2}, #{ptngro3}, #{ptinmag}, #{poststm}
, #{ptblctc}, #{ptnrord}, #{ptuseyn}
, to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{userData.useract}
, to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{userData.useract} )

