/* selectMdesmaList */ select concat(MDE.COMPKEY, MDE.PTNRKEY, MDE.DESTKEY) as ROWKEY , MDE.COMPKEY, MDE.PTNRKEY, MDE.DESTKEY , MDE.DENAMLC, MDE.DENATCD, MDE.DENAMKO, MDE.DENAMEN, MDE.DEADDR1 , MDE.DEADDR2, MDE.DEADDR3, MDE.DEPOSCD, MDE.DESTLAT, MDE.DESTLON , MDE.UNAVAT1, MDE.UNAVAT2, MDE.UNAVAT3, MDE.CUSGRO1, MDE.CUSGRO2 , MDE.CUSGRO3, MDE.SUNDAVL, MDE.MONDAVL, MDE.TUEDAVL, MDE.WEDDAVL , MDE.THUDAVL, MDE.FRIDAVL, MDE.SATDAVL, MDE.NATHAVL, MDE.DLVRQTM , MDE.ROUTEKY, MDE.UNLODMO, MDE.CUSPECD, MDE.CUSPERM, MDE.DEUSEYN , MPT.PTNAMLC , FN_COM_TODATE(MDE.CREDATE) as CREDATE, FN_COM_TOTIME(MDE.CRETIME) as CRETIME, fn_sy_usernam(MDE.COMPKEY, MDE.CREUSER) as CREUSER , FN_COM_TODATE(MDE.LMODATE) as LMODATE, FN_COM_TOTIME(MDE.LMOTIME) as LMOTIME, fn_sy_usernam(MDE.COMPKEY, MDE.LMOUSER) as LMOUSER , MDE.UPDTCHK from MDESMA MDE inner join MPTNMA MPT on (MDE.COMPKEY = MPT.COMPKEY and MDE.PTNRKEY = MPT.PTNRKEY) where MDE.COMPKEY = #{userData.compkey}
and upper(MPT.PTNAMLC) like concat('%' , upper(#{ptnamlc}), '%')
and upper(MDE.DENAMLC) like concat('%' , upper(#{denamlc}), '%')
order by MDE.COMPKEY, MDE.PTNRKEY, MDE.DESTKEY, MPT.PTNAMLC, MDE.DENAMLC

